#include <bits/stdc++.h>
using namespace std;
const int INF=2e9,N=1502;
struct Edge{
    int to,val;
};
int n,m,dist[N];
bool isin[N];
vector<Edge> g[N];
void SPFA(){
    for(int i=1;i<=n;i++)
        dist[i]=-INF;
    dist[1]=0;
    queue<int> q;
    q.push(1),isin[1]=1;
    while(q.size()){
        int f=q.front(),len=g[f].size();
        q.pop(),isin[f]=0;
        for(int i=0;i<len;i++)
            if(dist[g[f][i].to]<dist[f]+g[f][i].val){
                dist[g[f][i].to]=dist[f]+g[f][i].val;
                if(!isin[g[f][i].to])
                    q.push(g[f][i].to),isin[g[f][i].to]=1;
            }
    }
}
int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=m;i++){
        int u,v,w;
        scanf("%d%d%d",&u,&v,&w);
        g[u].push_back({v,w});
    }
    SPFA();
    if(dist[n]==-INF)
        printf("-1");
    else
        printf("%d",dist[n]);
    return 0;
}
